export const articles = {
  analysis: analysisArticles,
  'long-reads': longReadsArticles,
  briefs: [],
  interviews: [],
};

export function getArticle(section, slug) {
  const list = articles[section] || [];
  return list.find(a => a.slug === slug) || null;
}

export function getAllArticles() {
  return [
    ...analysisArticles,
    ...longReadsArticles,
  ];
}

export function getRecentArticles(count = 12) {
  return getAllArticles().slice(0, count);
}

